function phtDate() { const parts = new Intl.DateTimeFormat('en-US', { timeZone: 'Asia/Manila', year: 'numeric', month: '2-digit', day: '2-digit' }).formatToParts(new Date()); const pick = (type) => parts.find((part) => part.type === type).value; return `${pick('year')}-${pick('month')}-${pick('day')}`; }
const strip = (value) => String(value || '').replace(/<[^>]+>/g, ' ').replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&').replace(/\s+/g, ' ').trim();
const listingUrl = 'https://www.treasury.gov.ph/?cat=14';
const listingResponse = await fetch(listingUrl);
if (!listingResponse.ok) throw new Error(`BTr listing failed ${listingResponse.status}`);
const listingHtml = await listingResponse.text();
const links = [...listingHtml.matchAll(/<a[^>]+href=([^ >]+)[^>]*>([\s\S]*?)<\/a>/gi)].map((match) => { const href = String(match[1] || '').split(String.fromCharCode(34)).join('').split(String.fromCharCode(39)).join('').trim(); return { href, text: strip(match[2]) }; });
const resultLink = links.find((link) => /treasury bills auction results/i.test(link.text)) || links.find((link) => /treasury bills/i.test(link.text));
const postUrl = resultLink ? new URL(resultLink.href, listingUrl).toString() : listingUrl;
const postResponse = await fetch(postUrl);
if (!postResponse.ok) throw new Error(`BTr post failed ${postResponse.status}: ${postUrl}`);
const postHtml = await postResponse.text();
const text = strip(postHtml);
const patterns = [/91(?:-day)?\s+(?:t\s*-?\s*bill|treasury bill)[^0-9]{0,100}(\d+(?:\.\d+)?)/i, /\b91\b[^0-9]{0,100}(\d+(?:\.\d+)?)\s*%/i];
let parsed = null;
for (const pattern of patterns) { const match = text.match(pattern); if (match) { parsed = Number(match[1]); break; } }
if (!Number.isFinite(parsed)) throw new Error('Could not parse the 91-day T-Bill rate from the BTr page. Update the parser after checking the source page.');
const rate = parsed > 1 ? parsed / 100 : parsed;
if (rate <= 0 || rate > 0.20) throw new Error(`Parsed BTr rate looks wrong: ${rate}`);
return [{ json: { key: 'BTR_91D', label: '91-day T-Bill (BTr auction)', date: phtDate(), rate: Number(rate.toFixed(6)), source_url: postUrl } }];
